import{_ as a,o as n,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const d=JSON.parse('{"title":"CAT-12. 마케팅 & 영업 실무","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/marketing-sales.md","filePath":"hermes/benchmark/marketing-sales.md","lastUpdated":1781092690000}'),e={name:"hermes/benchmark/marketing-sales.md"};function i(t,s,c,o,r,u){return n(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="cat-12-마케팅-영업-실무" tabindex="-1">CAT-12. 마케팅 &amp; 영업 실무 <a class="header-anchor" href="#cat-12-마케팅-영업-실무" aria-label="Permalink to &quot;CAT-12. 마케팅 &amp; 영업 실무&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 카피라이팅, 캠페인 기획, 영업 자료, SNS 콘텐츠 등 <strong>매출에 직결되는 실무 문서</strong>를 만들 수 있는가?</p></blockquote><h2 id="이-카테고리가-중요한-이유" tabindex="-1">이 카테고리가 중요한 이유 <a class="header-anchor" href="#이-카테고리가-중요한-이유" aria-label="Permalink to &quot;이 카테고리가 중요한 이유&quot;">​</a></h2><p>마케팅/영업 문서는 <strong>설득력</strong>이 생명이다. 정확한 것만으로는 부족하고 <strong>읽는 사람이 행동하게 만들어야</strong> 한다.<br> 에이전트가 브랜드 톤을 이해하고, 타깃 고객에 맞는 메시지를 만드는지 평가한다.</p><h2 id="난이도-범례" tabindex="-1">난이도 범례 <a class="header-anchor" href="#난이도-범례" aria-label="Permalink to &quot;난이도 범례&quot;">​</a></h2><table tabindex="0"><thead><tr><th>레벨</th><th>의미</th><th>예상 소요</th></tr></thead><tbody><tr><td>⭐</td><td>기초 — 단일 콘텐츠, 명확한 타깃</td><td>2~3분</td></tr><tr><td>⭐⭐</td><td>중급 — 캠페인 수준, 복수 채널</td><td>3~5분</td></tr><tr><td>⭐⭐⭐</td><td>고급 — 전략 설계, 데이터 기반</td><td>5~10분</td></tr></tbody></table><hr><h2 id="ms-01-제품-랜딩-페이지-카피" tabindex="-1">MS-01. 제품 랜딩 페이지 카피 ⭐⭐ <a class="header-anchor" href="#ms-01-제품-랜딩-페이지-카피" aria-label="Permalink to &quot;MS-01. 제품 랜딩 페이지 카피 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>SaaS 제품의 랜딩 페이지 카피. 방문자를 가입/데모 신청으로 전환시키는 것이 목표.</p><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>B2B SaaS 제품의 랜딩 페이지 카피를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>제품 정보:</span></span>
<span class="line"><span>- 제품명: DataPulse</span></span>
<span class="line"><span>- 한 줄 설명: 중소기업용 실시간 비즈니스 대시보드</span></span>
<span class="line"><span>- 타깃: 직원 50~200명 규모 기업의 경영진, 팀장급</span></span>
<span class="line"><span>- 핵심 가치: 흩어진 데이터(매출, HR, 마케팅)를 한 화면에</span></span>
<span class="line"><span>- 경쟁 우위: 연동 설정 5분 (개발자 없이), 월 9만원부터</span></span>
<span class="line"><span>- 경쟁사: Tableau(비쌈/어려움), Google Data Studio(제한적)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>랜딩 페이지 구성:</span></span>
<span class="line"><span>1. 히어로 섹션</span></span>
<span class="line"><span>   - 헤드라인 (10자 이내 한국어)</span></span>
<span class="line"><span>   - 서브 헤드라인 (30자 이내)</span></span>
<span class="line"><span>   - CTA 버튼 텍스트 (2가지 제안)</span></span>
<span class="line"><span>   - 헤드라인 대안 3개 (A/B 테스트용)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 문제 제기 섹션</span></span>
<span class="line"><span>   - &quot;이런 경험 있으시죠?&quot; — 타깃 고객의 페인 포인트 3가지</span></span>
<span class="line"><span>   - 각 페인 포인트를 한 문장으로</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 솔루션 섹션</span></span>
<span class="line"><span>   - 핵심 기능 4가지 (아이콘 + 제목 + 설명 2줄)</span></span>
<span class="line"><span>   - 각 기능이 어떤 문제를 해결하는지 연결</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 사회적 증거 섹션</span></span>
<span class="line"><span>   - 고객 후기 3개 (가상, 하지만 자연스럽게)</span></span>
<span class="line"><span>   - 숫자 강조: &quot;OOO개 기업이 사용 중&quot;, &quot;평균 OO% 시간 절약&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 가격 섹션</span></span>
<span class="line"><span>   - 3 tier 가격표 카피 (Basic/Pro/Enterprise)</span></span>
<span class="line"><span>   - 각 tier의 한 줄 설명과 CTA</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. FAQ 섹션 (5개)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 최종 CTA 섹션</span></span>
<span class="line"><span>   - 행동 유도 카피 (긴급성 or 안심)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`marketing/datapulse-landing-copy.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>톤: 전문적이지만 친근한 IT 기업 톤.</span></span>
<span class="line"><span>&quot;혁신적인 솔루션&quot;같은 식상한 표현 금지.</span></span>
<span class="line"><span>모든 카피에 &quot;왜 이렇게 썼는지&quot; 간단한 코멘트 포함.</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 헤드라인의 임팩트 (10자 내에서 핵심 전달)</li><li>[ ] 페인 포인트의 공감 유발력 (타깃 입장)</li><li>[ ] 기능 설명이 &quot;기능&quot; 아닌 &quot;가치&quot; 중심인지</li><li>[ ] 고객 후기의 자연스러움 (광고체 아닌 실제 말투)</li><li>[ ] 가격 tier 카피의 차별화</li><li>[ ] CTA 텍스트의 행동 유도력</li><li>[ ] 식상한 마케팅 표현 배제</li></ul><hr><h2 id="ms-02-sns-콘텐츠-캘린더" tabindex="-1">MS-02. SNS 콘텐츠 캘린더 ⭐⭐ <a class="header-anchor" href="#ms-02-sns-콘텐츠-캘린더" aria-label="Permalink to &quot;MS-02. SNS 콘텐츠 캘린더 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-1" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-1" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>한 달 분량의 SNS 콘텐츠를 기획하는 능력.</p><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>4월 한 달간의 SNS 콘텐츠 캘린더를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>브랜드 정보:</span></span>
<span class="line"><span>- 브랜드: 오피스 간식 구독 서비스 &quot;스낵박스&quot;</span></span>
<span class="line"><span>- 타깃: 20~30대 직장인 (특히 사무직)</span></span>
<span class="line"><span>- 톤: 위트 있고, 직장인 공감, 살짝 B급 유머 OK</span></span>
<span class="line"><span>- 채널: 인스타그램 (피드 + 릴스), 링크드인</span></span>
<span class="line"><span>- 현재 팔로워: 인스타 1.2만, 링크드인 3천</span></span>
<span class="line"><span>- 주력 상품: 월 29,000원 구독 (과자+음료+건강간식 20종)</span></span>
<span class="line"><span>- 4월 이벤트: 신규 &quot;다이어트 간식 박스&quot; 출시 (4/15)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>콘텐츠 캘린더:</span></span>
<span class="line"><span>- 주 3회 인스타 (월/수/금), 주 1회 링크드인 (화)</span></span>
<span class="line"><span>- 총 포스팅: 인스타 12~13개 + 링크드인 4개</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 포스팅:</span></span>
<span class="line"><span>- 날짜, 채널</span></span>
<span class="line"><span>- 콘텐츠 유형: 사진/카드뉴스/릴스/캐러셀</span></span>
<span class="line"><span>- 주제 &amp; 콘셉트</span></span>
<span class="line"><span>- 캡션 전문 (해시태그 포함)</span></span>
<span class="line"><span>- 이미지 디렉션 (촬영/디자인팀에 전달할 설명)</span></span>
<span class="line"><span>- 목적: 인지도/참여/전환 중 어느 것</span></span>
<span class="line"><span></span></span>
<span class="line"><span>월간 전략:</span></span>
<span class="line"><span>- Week 1: 4월 시작, 직장인 공감 콘텐츠 (참여 유도)</span></span>
<span class="line"><span>- Week 2: 신제품 티저 (궁금증 유발)</span></span>
<span class="line"><span>- Week 3: 다이어트 간식 박스 출시 (전환 집중)</span></span>
<span class="line"><span>- Week 4: 사용자 후기 &amp; 리그램 (사회적 증거)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>링크드인:</span></span>
<span class="line"><span>- 브랜드 스토리, 팀 소개, 업계 인사이트 (B2B 톤)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`marketing/snackbox-april-content-calendar.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>주의: &quot;지금 바로 구매하세요!!&quot; 같은 노골적 광고 금지.</span></span>
<span class="line"><span>자연스러운 콘텐츠 안에 브랜드 메시지를 녹여야 함.</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 콘텐츠 유형의 다양성 (사진, 릴스, 캐러셀 균형)</li><li>[ ] 캡션의 톤 일관성 (직장인 공감 + 위트)</li><li>[ ] 해시태그 전략의 현실성</li><li>[ ] 이미지 디렉션의 구체성 (실제 촬영 가능 수준)</li><li>[ ] 4주간 스토리 아크 (공감→티저→출시→후기)</li><li>[ ] 링크드인 vs 인스타 톤 차별화</li><li>[ ] 노골적 광고 배제, 자연스러운 CTA</li></ul><hr><h2 id="ms-03-이메일-마케팅-시퀀스" tabindex="-1">MS-03. 이메일 마케팅 시퀀스 ⭐⭐ <a class="header-anchor" href="#ms-03-이메일-마케팅-시퀀스" aria-label="Permalink to &quot;MS-03. 이메일 마케팅 시퀀스 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-2" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-2" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>가입부터 결제까지 이어지는 이메일 자동화 시퀀스.</p><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SaaS 서비스의 무료 체험 → 유료 전환을 위한 이메일 시퀀스를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스 정보:</span></span>
<span class="line"><span>- 서비스: &quot;미팅노트&quot; — AI 기반 회의 자동 요약/기록 도구</span></span>
<span class="line"><span>- 무료 체험: 14일</span></span>
<span class="line"><span>- 유료: 월 12,000원/인 (팀 5인 이상 20% 할인)</span></span>
<span class="line"><span>- 타깃: 기업 팀장급 (회의가 많은 사람)</span></span>
<span class="line"><span>- 핵심 기능: 실시간 녹음 → AI 요약 → 액션아이템 추출 → 슬랙 공유</span></span>
<span class="line"><span></span></span>
<span class="line"><span>이메일 시퀀스 (8통):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Day 0 — 가입 환영</span></span>
<span class="line"><span>Day 1 — 첫 사용 가이드 (3분 만에 시작하기)</span></span>
<span class="line"><span>Day 3 — 팁: &quot;회의 시간 50% 줄이는 3가지 설정&quot;</span></span>
<span class="line"><span>Day 5 — 사례: &quot;이 팀은 주간 회의 2시간 → 30분으로 줄였습니다&quot;</span></span>
<span class="line"><span>Day 7 — 중간 체크: &quot;잘 사용하고 계신가요?&quot; + 미사용자 재활성화</span></span>
<span class="line"><span>Day 10 — 팀 기능 소개: &quot;팀원을 초대하면 더 강력합니다&quot;</span></span>
<span class="line"><span>Day 12 — 마감 임박: &quot;무료 체험이 2일 남았습니다&quot;</span></span>
<span class="line"><span>Day 14 — 최종: 전환 유도 or 연장 제안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 이메일:</span></span>
<span class="line"><span>- 제목(Subject line) 3가지 대안 (A/B/C 테스트용)</span></span>
<span class="line"><span>- 프리헤더(Preview text)</span></span>
<span class="line"><span>- 본문 전체 (HTML 메일 기준, 마크다운으로 작성)</span></span>
<span class="line"><span>- CTA 버튼 텍스트</span></span>
<span class="line"><span>- 발신자 이름/주소 (예: &quot;미팅노트 팀 박서연&quot;)</span></span>
<span class="line"><span>- 세그먼트 조건: 이 메일을 받는 사람의 조건</span></span>
<span class="line"><span>  (예: Day 7은 &quot;3일 내 미접속 사용자만&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`marketing/meetingnote-email-sequence.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>톤: 조언해주는 동료 느낌. &quot;세일즈맨이 쫓아오는 느낌&quot; 절대 금지.</span></span>
<span class="line"><span>각 이메일이 독립적으로도 가치 있는 콘텐츠여야 함 (순수 광고 X).</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] Subject line의 오픈율 유도력 (호기심, 숫자, 긴급성 등)</li><li>[ ] Day별 목적의 명확한 차별화</li><li>[ ] Day 7 세그먼트의 현실적 설정 (미사용자 분기)</li><li>[ ] 사례 이메일(Day 5)의 설득력</li><li>[ ] Day 12~14 마감 압박의 적절한 수위</li><li>[ ] &quot;세일즈맨 느낌&quot; 배제</li><li>[ ] CTA 텍스트의 행동 유도력</li></ul><hr><h2 id="ms-04-영업-제안-프레젠테이션" tabindex="-1">MS-04. 영업 제안 프레젠테이션 ⭐⭐⭐ <a class="header-anchor" href="#ms-04-영업-제안-프레젠테이션" aria-label="Permalink to &quot;MS-04. 영업 제안 프레젠테이션 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-3" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-3" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객 미팅에서 사용할 영업 제안 발표 구성.</p><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>고객 미팅용 영업 제안 프레젠테이션 스크립트를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>상황:</span></span>
<span class="line"><span>- 우리: HR SaaS 기업 &quot;피플웍스&quot; (근태, 급여, 평가 통합 솔루션)</span></span>
<span class="line"><span>- 고객: 중견 제조업 &quot;K산업&quot; (직원 500명, 공장 3개)</span></span>
<span class="line"><span>- 현재 고객 상황: </span></span>
<span class="line"><span>  - 근태: 수기 출퇴근 기록 + 엑셀 정리 (매월 담당자 3일 소요)</span></span>
<span class="line"><span>  - 급여: 세무사 외주 (월 150만원)</span></span>
<span class="line"><span>  - 평가: 연 1회 종이 양식</span></span>
<span class="line"><span>  - 이슈: 공장별 교대근무 관리 복잡, 급여 오류 월 2~3건, 평가 형식적</span></span>
<span class="line"><span></span></span>
<span class="line"><span>미팅 참석자:</span></span>
<span class="line"><span>- 고객측: HR팀장(의사결정자), 경영기획실장(예산 권한), IT담당자(기술 검토)</span></span>
<span class="line"><span>- 우리측: 영업 매니저(나), SE(기술 설명)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>발표 구성 (30분):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`sales/kcompany-proposal-deck.md\` — 슬라이드 스토리보드 (15장)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   파트 1: 고객 이해 (5분, 3장)</span></span>
<span class="line"><span>   - K산업의 현재 HR 프로세스를 우리가 이해하고 있다는 것 보여주기</span></span>
<span class="line"><span>   - 페인 포인트를 고객의 언어로 정리</span></span>
<span class="line"><span>   - &quot;이게 매년 얼마의 비용인지&quot; 숫자로 환산</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   파트 2: 솔루션 (10분, 5장)</span></span>
<span class="line"><span>   - 피플웍스가 이 문제를 어떻게 해결하는지</span></span>
<span class="line"><span>   - 제조업 특화 기능 강조 (교대근무, 공장별 관리)</span></span>
<span class="line"><span>   - 데모 시나리오 (어떤 화면을 보여줄지)</span></span>
<span class="line"><span>   - 유사 제조업 고객 사례 (가상)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   파트 3: 도입 제안 (5분, 4장)</span></span>
<span class="line"><span>   - 도입 일정 (3개월)</span></span>
<span class="line"><span>   - 가격 (비교 표: 현재 비용 vs 피플웍스)</span></span>
<span class="line"><span>   - ROI 계산 (담당자 3일 절감, 세무사 비용, 오류 감소)</span></span>
<span class="line"><span>   - 왜 지금 도입해야 하는지</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   파트 4: 클로징 (5분, 3장)</span></span>
<span class="line"><span>   - 다음 단계 제안 (무료 PoC 2주)</span></span>
<span class="line"><span>   - Q&amp;A 대비 예상 질문 &amp; 답변 10개</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>2. \`sales/kcompany-objection-handling.md\` — 반론 대응 가이드</span></span>
<span class="line"><span>   - &quot;가격이 비싸다&quot; → (현재 숨은 비용 대비 설명)</span></span>
<span class="line"><span>   - &quot;기존 시스템 바꾸기 싫다&quot; → (병행 운영 가능, 마이그레이션 지원)</span></span>
<span class="line"><span>   - &quot;공장에서 태블릿 도입이 어렵다&quot; → (키오스크 모드, 오프라인 동기화)</span></span>
<span class="line"><span>   - &quot;데이터 보안이 걱정된다&quot; → (ISO 인증, 온프레미스 옵션)</span></span>
<span class="line"><span>   - &quot;IT 담당자가 부족하다&quot; → (SaaS라 관리 불필요, 고객성공팀 지원)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>3. \`sales/kcompany-followup-email.md\` — 미팅 후 팔로업 이메일</span></span>
<span class="line"><span>   - 미팅 감사 + 핵심 논의사항 요약</span></span>
<span class="line"><span>   - 약속한 자료 첨부 안내</span></span>
<span class="line"><span>   - 다음 단계 (PoC 일정) 제안</span></span>
<span class="line"><span>   - 톤: 세일즈 압박 없이 자연스럽게</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 고객 이해 파트: K산업의 페인 포인트를 &quot;고객의 언어&quot;로 표현했는지</li><li>[ ] 비용 환산의 현실성 (월 3일 × 인건비 + 세무사 150만 등)</li><li>[ ] 제조업 특화 기능 강조의 설득력</li><li>[ ] ROI 계산의 구체성</li><li>[ ] 반론 대응의 현실성과 설득력</li><li>[ ] 미팅 참석자별 관심사 고려 (HR팀장 vs 경영기획실장 vs IT)</li><li>[ ] 팔로업 이메일의 톤 (압박 없는 프로페셔널)</li></ul><hr><h2 id="ms-05-브랜드-가이드라인" tabindex="-1">MS-05. 브랜드 가이드라인 ⭐⭐ <a class="header-anchor" href="#ms-05-브랜드-가이드라인" aria-label="Permalink to &quot;MS-05. 브랜드 가이드라인 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-4" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-4" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>브랜드 일관성을 유지하기 위한 가이드라인 문서.</p><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>스타트업의 브랜드 가이드라인을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>브랜드:</span></span>
<span class="line"><span>- 이름: &quot;플로우(Flow)&quot;</span></span>
<span class="line"><span>- 서비스: 프리랜서-기업 매칭 플랫폼</span></span>
<span class="line"><span>- 미션: &quot;일하는 방식의 자유를 연결하다&quot;</span></span>
<span class="line"><span>- 타깃: 프리랜서(20~40대 전문직) + 기업 HR/프로젝트 매니저</span></span>
<span class="line"><span>- 경쟁: 크몽, 숨고, 탤런트뱅크</span></span>
<span class="line"><span>- 포지셔닝: &quot;프리미엄 전문가 매칭&quot; (아무나 안 받음, 검증된 전문가)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>가이드라인:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`brand/flow-brand-guidelines.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   A. 브랜드 에센스</span></span>
<span class="line"><span>   - 미션, 비전, 핵심 가치 3가지</span></span>
<span class="line"><span>   - 브랜드 퍼스낼리티 (형용사 5개 + 설명)</span></span>
<span class="line"><span>   - &quot;플로우는 OOO이다 / 플로우는 OOO이 아니다&quot; 비교표</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   B. 보이스 &amp; 톤 가이드</span></span>
<span class="line"><span>   - 전반적 톤: 전문적이면서 따뜻한</span></span>
<span class="line"><span>   - 채널별 톤 변주:</span></span>
<span class="line"><span>     - 웹사이트: 신뢰감 + 세련됨</span></span>
<span class="line"><span>     - 인스타그램: 친근 + 영감</span></span>
<span class="line"><span>     - 이메일: 개인적 + 도움</span></span>
<span class="line"><span>     - 고객센터: 공감 + 해결 중심</span></span>
<span class="line"><span>   - 용어 가이드:</span></span>
<span class="line"><span>     - 써야 하는 단어: &quot;전문가&quot;, &quot;파트너&quot;, &quot;연결&quot;</span></span>
<span class="line"><span>     - 쓰지 말아야 하는 단어: &quot;알바&quot;, &quot;저렴한&quot;, &quot;빠른&quot;</span></span>
<span class="line"><span>   - 예문: 같은 내용을 좋은 예 / 나쁜 예로 10쌍</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   C. 메시지 프레임워크</span></span>
<span class="line"><span>   - 메인 타깃별 핵심 메시지:</span></span>
<span class="line"><span>     - 프리랜서: &quot;당신의 전문성에 맞는 프로젝트만&quot;</span></span>
<span class="line"><span>     - 기업: &quot;검증된 전문가, 확실한 결과&quot;</span></span>
<span class="line"><span>   - 기능별 메시지: 매칭, 계약, 결제, 리뷰 각각</span></span>
<span class="line"><span>   - 경쟁사 대비 차별화 메시지</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   D. 글쓰기 규칙</span></span>
<span class="line"><span>   - 문장 길이 (30자 이내 권장)</span></span>
<span class="line"><span>   - 능동태 사용, 이중 부정 금지</span></span>
<span class="line"><span>   - 숫자 표기 규칙 (만 단위, % 표기)</span></span>
<span class="line"><span>   - 외래어/영문 표기 원칙</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 브랜드 퍼스낼리티의 차별성 (경쟁사와 구분)</li><li>[ ] 채널별 톤 변주의 구체성</li><li>[ ] 용어 가이드의 실용성 (&quot;이건 쓰고 이건 쓰지 마&quot;)</li><li>[ ] 좋은 예/나쁜 예 10쌍의 명확한 차이</li><li>[ ] 타깃별 메시지의 차별화 (프리랜서 vs 기업)</li><li>[ ] 글쓰기 규칙의 구체성</li><li>[ ] 전체적으로 &quot;읽고 바로 적용 가능한&quot; 수준</li></ul><hr><h2 id="ms-06-캠페인-기획서" tabindex="-1">MS-06. 캠페인 기획서 ⭐⭐⭐ <a class="header-anchor" href="#ms-06-캠페인-기획서" aria-label="Permalink to &quot;MS-06. 캠페인 기획서 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-5" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-5" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>마케팅 캠페인을 기획부터 측정까지 종합적으로 설계.</p><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>신규 고객 유치 캠페인 기획서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>배경:</span></span>
<span class="line"><span>- 서비스: 기업용 화상회의 솔루션 &quot;MeetHub&quot;</span></span>
<span class="line"><span>- 현황: MAU 3,000 (유료 고객 200사, ARPU 8만원/월)</span></span>
<span class="line"><span>- 목표: 3개월 내 유료 고객 200 → 350사 (+75%)</span></span>
<span class="line"><span>- 예산: 5,000만원</span></span>
<span class="line"><span>- 경쟁 이벤트: 줌(Zoom) 가격 인상 발표 (4월)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>캠페인 기획:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`marketing/meethub-campaign-plan.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   A. 캠페인 개요</span></span>
<span class="line"><span>   - 캠페인명 (임팩트 있는 이름)</span></span>
<span class="line"><span>   - 기간, 예산, 목표 KPI</span></span>
<span class="line"><span>   - 핵심 메시지: &quot;줌에서 갈아타야 할 3가지 이유&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   B. 타깃 세그먼트 (3개)</span></span>
<span class="line"><span>   - 세그먼트 1: 줌 유료 사용 중소기업 (가격 민감)</span></span>
<span class="line"><span>   - 세그먼트 2: 화상회의 미도입 기업 (코로나 후 하이브리드 전환)</span></span>
<span class="line"><span>   - 세그먼트 3: 기존 무료 체험 후 이탈한 사용자 (재활성화)</span></span>
<span class="line"><span>   - 각 세그먼트별 페인 포인트, 핵심 메시지, 채널</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   C. 채널 전략 &amp; 예산 배분</span></span>
<span class="line"><span>   - Google Ads (키워드: &quot;줌 대안&quot;, &quot;화상회의 비교&quot;) — 예산, 예상 CPC, 목표 클릭</span></span>
<span class="line"><span>   - 네이버 검색광고 — 예산, 키워드 전략</span></span>
<span class="line"><span>   - LinkedIn Ads — B2B 타깃팅</span></span>
<span class="line"><span>   - 콘텐츠 마케팅: 비교 블로그 포스트, 전환 가이드</span></span>
<span class="line"><span>   - 이메일: 이탈 사용자 재활성화 캠페인</span></span>
<span class="line"><span>   - 오프라인: IT 관련 세미나 후원 1회</span></span>
<span class="line"><span>   - 채널별 예산 배분 + 예상 ROI</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   D. 콘텐츠 계획</span></span>
<span class="line"><span>   - 블로그: &quot;줌 vs MeetHub 완전 비교&quot; (SEO 타깃)</span></span>
<span class="line"><span>   - 랜딩 페이지: &quot;줌에서 MeetHub으로&quot; 마이그레이션 가이드</span></span>
<span class="line"><span>   - 영상: 전환 후기 인터뷰 (가상 시나리오)</span></span>
<span class="line"><span>   - 프로모션: &quot;줌에서 갈아타면 3개월 50% 할인&quot;</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   E. 실행 타임라인 (12주, 주 단위)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   F. 측정 &amp; 최적화</span></span>
<span class="line"><span>   - 주간 KPI 대시보드 (어떤 지표를 볼 것인가)</span></span>
<span class="line"><span>   - A/B 테스트 계획 (광고 소재, 랜딩페이지, 이메일)</span></span>
<span class="line"><span>   - 4주차/8주차 리뷰 포인트 (예산 재배분 기준)</span></span>
<span class="line"><span>   - 최종 보고서 구조</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`marketing/meethub-campaign-plan.md\`</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 줌 가격 인상이라는 기회를 전략에 반영</li><li>[ ] 3개 세그먼트의 차별화된 접근</li><li>[ ] 채널별 예산 배분의 논리 (5천만원 최적 배분)</li><li>[ ] 예상 CPC, 전환율 등 수치의 현실성</li><li>[ ] &quot;줌에서 갈아타면&quot; 프로모션의 설계</li><li>[ ] 12주 타임라인의 주별 구체성</li><li>[ ] A/B 테스트 계획의 실용성</li></ul><hr><h2 id="ms-07-고객-성공-스토리-인터뷰-가이드" tabindex="-1">MS-07. 고객 성공 스토리 인터뷰 가이드 ⭐ <a class="header-anchor" href="#ms-07-고객-성공-스토리-인터뷰-가이드" aria-label="Permalink to &quot;MS-07. 고객 성공 스토리 인터뷰 가이드 :star:&quot;">​</a></h2><h3 id="시나리오-배경-6" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-6" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객 성공 사례를 수집하기 위한 인터뷰 설계.</p><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>고객 인터뷰를 진행해서 성공 사례를 수집하려고 해. </span></span>
<span class="line"><span>인터뷰 가이드와 사후 정리 양식을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>목적: 마케팅용 고객 사례(Case Study) 수집</span></span>
<span class="line"><span>인터뷰 대상: 우리 SaaS를 1년 이상 사용한 고객사 담당자</span></span>
<span class="line"><span>인터뷰 시간: 30분 (화상 또는 대면)</span></span>
<span class="line"><span>활용: 웹사이트 사례 페이지, 영업 자료, 블로그</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`marketing/customer-interview-guide.md\`</span></span>
<span class="line"><span>   - 인터뷰 전 준비 체크리스트</span></span>
<span class="line"><span>     - 고객 정보 사전 조사 (계약 이력, 사용 데이터, CS 이력)</span></span>
<span class="line"><span>     - 장비 준비 (녹음 동의, 카메라)</span></span>
<span class="line"><span>   - 인터뷰 구조 (30분 배분)</span></span>
<span class="line"><span>     - 아이스브레이킹 (3분)</span></span>
<span class="line"><span>     - 도입 배경 (7분): &quot;이전에는 어떻게 하셨어요?&quot;</span></span>
<span class="line"><span>     - 도입 과정 (5분): &quot;처음 사용할 때 어땠어요?&quot;</span></span>
<span class="line"><span>     - 성과 (10분): &quot;구체적으로 뭐가 달라졌어요?&quot;</span></span>
<span class="line"><span>     - 추천 (3분): &quot;다른 분께 추천한다면?&quot;</span></span>
<span class="line"><span>     - 클로징 (2분)</span></span>
<span class="line"><span>   - 각 파트별 질문 (주 질문 + 꼬리 질문)</span></span>
<span class="line"><span>   - 좋은 답변을 이끄는 프로빙(probing) 기법</span></span>
<span class="line"><span>     - &quot;구체적으로 어떤 상황이었나요?&quot;</span></span>
<span class="line"><span>     - &quot;숫자로 말씀해주실 수 있나요?&quot;</span></span>
<span class="line"><span>     - &quot;그때 기분이 어떠셨어요?&quot; (감정 유도)</span></span>
<span class="line"><span>   - 인터뷰이가 말을 잘 안 할 때 대처법</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`marketing/interview-summary-template.md\`</span></span>
<span class="line"><span>   - 인터뷰 결과 정리 양식</span></span>
<span class="line"><span>   - 핵심 인용문 (Quote) 3~5개 추출</span></span>
<span class="line"><span>   - Before/After 정리</span></span>
<span class="line"><span>   - 사용 가능한 정량 데이터</span></span>
<span class="line"><span>   - 사례 유형 분류 (비용 절감, 생산성 향상, 매출 증가 등)</span></span>
<span class="line"><span>   - 활용 동의 확인 (회사명 공개, 담당자명 공개, 사진 사용 등)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. \`marketing/interview-request-email.md\`</span></span>
<span class="line"><span>   - 고객에게 인터뷰 요청하는 이메일 템플릿</span></span>
<span class="line"><span>   - 인센티브 제안 (다음 달 무료, 기프트카드 등)</span></span>
<span class="line"><span>   - 인터뷰가 부담스럽지 않다는 느낌</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 질문의 구조 (개방형, 구체화 유도)</li><li>[ ] 프로빙 기법의 실용성</li><li>[ ] 정량 데이터를 끌어내는 질문 설계</li><li>[ ] 인터뷰 결과 정리 양식의 완성도</li><li>[ ] Quote 추출 가이드의 구체성</li><li>[ ] 인터뷰 요청 이메일의 부담 없는 톤</li><li>[ ] 동의 확인 항목의 빈틈 없음</li></ul><hr><h2 id="ms-08-경쟁사-리뷰-분석-포지셔닝" tabindex="-1">MS-08. 경쟁사 리뷰 분석 &amp; 포지셔닝 ⭐⭐ <a class="header-anchor" href="#ms-08-경쟁사-리뷰-분석-포지셔닝" aria-label="Permalink to &quot;MS-08. 경쟁사 리뷰 분석 &amp; 포지셔닝 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-7" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-7" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객 리뷰 데이터에서 경쟁 인사이트를 추출하는 능력.</p><h3 id="프롬프트-7" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-7" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>경쟁사 리뷰를 분석해서 우리 제품 포지셔닝 전략을 수립해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>먼저 가상의 앱스토어 리뷰 데이터를 만들어:</span></span>
<span class="line"><span>\`marketing/competitor-reviews.json\` — 3개 경쟁 앱의 리뷰 각 30개 (총 90개)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>경쟁사:</span></span>
<span class="line"><span>- 앱 A &quot;노션(Notion)&quot;: 올인원 협업 도구</span></span>
<span class="line"><span>- 앱 B &quot;슬랙(Slack)&quot;: 메신저 기반 협업</span></span>
<span class="line"><span>- 앱 C &quot;먼데이(Monday)&quot;: 프로젝트 관리 특화</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 리뷰:</span></span>
<span class="line"><span>- rating (1~5), date, title, body (한국어, 2~5문장)</span></span>
<span class="line"><span>- 분포: 5점 30%, 4점 25%, 3점 20%, 2점 15%, 1점 10%</span></span>
<span class="line"><span>- 긍정/부정 키워드가 자연스럽게 포함</span></span>
<span class="line"><span></span></span>
<span class="line"><span>분석:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`marketing/review-analysis-report.md\`</span></span>
<span class="line"><span>1. 경쟁사별 리뷰 요약</span></span>
<span class="line"><span>   - 평균 별점, 분포</span></span>
<span class="line"><span>   - 긍정 키워드 TOP 5, 부정 키워드 TOP 5</span></span>
<span class="line"><span>   - 고객이 가장 좋아하는 기능 / 가장 불만인 기능</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 경쟁사 약점 매핑</span></span>
<span class="line"><span>   - 공통 불만 (3사 모두에서 나오는)</span></span>
<span class="line"><span>   - 각 앱 고유 약점</span></span>
<span class="line"><span>   - 불만→우리 기회 연결</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 포지셔닝 전략</span></span>
<span class="line"><span>   - 경쟁사 약점을 공략하는 우리 제품 메시지</span></span>
<span class="line"><span>   - 비교 광고 카피 3종 (직접 비교 vs 암시적 비교)</span></span>
<span class="line"><span>   - &quot;왜 OO에서 갈아타야 하나&quot; 마이그레이션 가이드 구성안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>분석 스크립트: \`marketing/analyze_reviews.py\` (JSON 파싱 → 키워드 추출 → 리포트)</span></span></code></pre></div><h3 id="평가-포인트-7" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-7" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 가상 리뷰의 현실성 (실제 앱스토어 리뷰 같은지)</li><li>[ ] 키워드 추출의 정확성</li><li>[ ] 경쟁사 약점→기회 연결의 논리성</li><li>[ ] 비교 광고 카피의 전략적 수준</li><li>[ ] 마이그레이션 가이드 구성의 설득력</li><li>[ ] 분석 스크립트의 실행 가능성</li></ul>`,70)])])}const q=a(e,[["render",i]]);export{d as __pageData,q as default};
